const COURSE_DATA = {"title": "Cyber Security", "modules": [{"number": 1, "name": "Getting Started", "description": ["Every organization is responsible for ensuring cyber security. The ability to protect its information systems from impairment or even theft is essential to success. Implementing effective security measures will not only offer liability protection; it will also increase efficiency and productivity."], "lessons": [], "quizzes": [], "case_study": null, "images": ["assets/images/m01-getting-started-hero.png"], "objectives": ["Research has consistently demonstrated that when clear goals are associated with learning, it occurs more easily and rapidly. With that in mind, let\u2019s review our goals for today.\n\nAt the end of this workshop, participants should be able to:\n\nUnderstand different types of malware and security breaches\nKnow the types of cyber attacks to look out for\nDevelop effective prevention methods"]}, {"number": 2, "name": "Why Your Office Needs Administrative Procedures", "description": ["Module 2: Cyber security Fundamentals", "Before developing and implementing security measures to prevent cyber attacks, you must understand basic concepts associated with cyber security and what cyber attacks are. The method(s) of cyber security that a company uses should be tailored to fit the needs of the organization."], "lessons": [{"title": "What is Cyberspace?", "body": ["Cyberspace is the environment where computer transactions take place. This specifically refers to computer-to-computer activity. Although there is no \u201cphysical\u201d space that makes up cyberspace, with the stroke of a few keys on a keyboard, one can connect with others around the world.\n\nExamples of items included in cyberspace are:\n\u00b7\tNetworks\n\u00b7\tDevices\n\u00b7\tSoftware\n\u00b7\tProcesses\n\u00b7\tInformation storage\n\u00b7\tApplications"], "images": []}, {"title": "What is Cyber Security?", "body": ["As previously mentioned, cyber security is the implementation of methods to prevent attacks on a company\u2019s information systems. This is done to avoid disruption of the company\u2019s productivity. Not only does cyber security include controlling physical access to the system\u2019s hardware, it protects from danger that may come via network access or the injection of code."], "images": []}, {"title": "Why is Cyber Security Important?", "body": ["Cyber security is crucial to a business for a myriad of reasons. The two this section will focus on are data security breaches and sabotage. Both can have dire effects on a company and/or its clients.\nData security breaches can compromise secure information such as:\n\u00b7\tNames and social security numbers\n\u00b7\tCredit card and bank details\n\u00b7\tTrade secrets\n\u00b7\tIntellectual property\nComputer sabotage serves to disable a company\u2019s computers or network to impede the company\u2019s ability to conduct business."], "images": []}, {"title": "What is a Hacker?", "body": ["In simple terms, a hacker is an individual or group of individuals who use their knowledge of technology to break into computer systems and networks, using a variety of tools to gain access to and utilize other people\u2019s data for devious reasons.\nThere are 3 main types of hackers. They are:\n\u00b7\tGrey hats: These hackers do so \u201cfor the fun of it\u201d.\n\u00b7\tBlack hats: These hackers have malevolent reasons for doing so, such as stealing and/or selling data for monetary gain.\n\u00b7\tWhite hats: These hackers are employed by companies to hack into systems to find where the company is vulnerable, with the intention of ensuring the safety of the data from hackers with ill intentions."], "images": []}], "quizzes": [{"question": "Cyberspace refers to which of the following?", "choices": [{"text": "Computer-to-computer activity", "correct": true}, {"text": "Individual-to-individual activity", "correct": false}, {"text": "Supervisor-to-employee activity", "correct": false}, {"text": "Computer-to-physical location activity", "correct": false}]}, {"question": "What is an item that is included in cyberspace?", "choices": [{"text": "Network", "correct": false}, {"text": "Software", "correct": false}, {"text": "Application", "correct": false}, {"text": "All of the above", "correct": true}]}, {"question": "Why is cyber security implemented?", "choices": [{"text": "To speed up the network of a company\u2019s computers", "correct": false}, {"text": "To avoid the disruption of a company\u2019s business", "correct": true}, {"text": "To increase the number of clients a company has", "correct": false}, {"text": "To lessen the number of employees a company employs", "correct": false}]}, {"question": "Cyber security  helps control physical access to and prevents danger that may come in from:", "choices": [{"text": "Hardware", "correct": false}, {"text": "Network access", "correct": false}, {"text": "Code injection", "correct": false}, {"text": "All of the above", "correct": true}]}, {"question": "What type of information is NOT secure information that is likely to be compromised in a data security breach?", "choices": [{"text": "Intellectual property", "correct": false}, {"text": "Credit card information", "correct": false}, {"text": "The name of a company\u2019s CEO", "correct": true}, {"text": "Social security numbers", "correct": false}]}, {"question": "What is the main purpose of computer sabotage?", "choices": [{"text": "To disable a company\u2019s computers or networks to prevent it from conducting business.", "correct": true}, {"text": "To disable a company\u2019s computers or networks to prevent it from being able to obtain a business license.", "correct": false}, {"text": "To disable a company\u2019s computers or networks to prevent it from being able to hire employees.", "correct": false}, {"text": "To disable a company\u2019s computers or networks to prevent it from being able to give its employees raises.", "correct": false}]}, {"question": "Why do \u201cgrey hat\u201d hackers typically hack into computers?", "choices": [{"text": "To steal data for monetary gain", "correct": false}, {"text": "For the fun of it", "correct": true}, {"text": "To find vulnerabilities in a computer system so the company can fix them before hackers with bad intentions can exploit them", "correct": false}, {"text": "To sell data for monetary gain", "correct": false}]}, {"question": "Why do \u201cwhite hat\u201d hackers typically hack into computers?", "choices": [{"text": "To steal data for monetary gain", "correct": false}, {"text": "For the fun of it", "correct": false}, {"text": "To find vulnerabilities in a computer system so the company can fix them before hackers with bad intentions can exploit them", "correct": true}, {"text": "To sell data for monetary gain", "correct": false}]}, {"question": "What type of business are Patrick and Willow opening?", "choices": [{"text": "Restaurant", "correct": false}, {"text": "Flower shop", "correct": false}, {"text": "Answering service", "correct": true}, {"text": "Bike shop", "correct": false}]}, {"question": "Does Willow think they need security for their computers? What is her reasoning?", "choices": [{"text": "No, because their business is small", "correct": false}, {"text": "Yes, because they are vulnerable to hackers", "correct": true}, {"text": "No, because the type of business they run doesn\u2019t require it", "correct": false}, {"text": "Yes, because federal law requires them to have it", "correct": false}]}], "case_study": {"body": [], "video": "assets/videos/m02-why-your-office-needs-administ-case-study.mp4", "poster": "assets/posters/m02-why-your-office-needs-administ-case-study.jpg"}, "images": ["assets/images/m02-why-your-office-needs-administ-hero.png"], "has_results": true}, {"number": 3, "name": "Types of Malware", "description": ["\u201dMalware\u201d is the shortened form for malicious software, which is intrusive software, used to perform actions such as interrupting computer operations and obtaining sensitive information. Acquiring access to private computer systems and brandishing unsolicited advertising are also characteristic of Malware."], "lessons": [{"title": "Worms", "body": ["A computer worm is an independent malware program that reproduces itself to infect other computers. It can spread to other computers without having to attach to an existing program, but still causes some form of damage to the network.\nDamage done by worms includes:\n\u00b7\tBandwidth consumption\n\u00b7\tStopping active anti-malware service\n\u00b7\tImmobilizing Safe Mode\n\u00b7\tHindering Windows auto update"], "images": []}, {"title": "Viruses", "body": ["A computer virus is a program that hides within a harmless program that reproduces itself to perform actions such as destroying data. It can infect files and when the file is opened, spread the virus throughout your computer. The virus will further spread if the infected file is shared with others.\n\nDamage done by viruses includes:\n\u00b7\tCorrupting files\n\u00b7\tComputer slowdown\n\u00b7\tTaking over basic functions of the operating system"], "images": []}, {"title": "Spyware", "body": ["The main purpose of Spyware is to obtain information about an individual or company without their knowledge or consent. The data gathered from this act of \u201cspying\u201d is sometimes sent to another entity. It can also be used to gain control over one\u2019s computer without the user realizing it. It is commonly used to track the user\u2019s movements and bombard him/her with pop-up ads.\nDamage done by spyware includes:\n\u00b7\tCollecting personal information\n\u00b7\tInstalling unsolicited software\n\u00b7\tRedirecting web browsers\n\u00b7\tChanging computer settings\n\u00b7\tSlowing down Internet connection"], "images": []}, {"title": "Trojans", "body": ["Trojans gain access into computers by misleading users of what it is truly meant to do. They spread in sneaky ways. For example, a user may receive an email attachment that appears to be legitimate, but when he/she opens it, it in fact gives the attacker the opportunity to obtain the user\u2019s personal information, such as banking details and passwords.\nDamage done by Trojans includes:\n\u00b7\tCrashing the computer\n\u00b7\tDeleting files\n\u00b7\tCorrupting data\n\u00b7\tLogging keystrokes"], "images": []}], "quizzes": [{"question": "How do worms work?", "choices": [{"text": "They are always downloaded as email attachments", "correct": false}, {"text": "They are automatically installed on every computer", "correct": false}, {"text": "They must attach themselves to existing programs in order to spread", "correct": false}, {"text": "They reproduce themselves to infect other computers", "correct": true}]}, {"question": "Which of the following does the lesson NOT list as damage that worms can cause?", "choices": [{"text": "Bandwidth consumption", "correct": false}, {"text": "Immobilizing Safe Mode", "correct": false}, {"text": "Corrupting files", "correct": true}, {"text": "Stopping active anti-malware service", "correct": false}]}, {"question": "When can infected files infect other computers?", "choices": [{"text": "When the file is shared with other computers", "correct": true}, {"text": "Whether or not the file is shared with other computers", "correct": false}, {"text": "They automatically infect other computers within the same network of the originally infected computer", "correct": false}, {"text": "Never", "correct": false}]}, {"question": "Which of the following does the lesson NOT list as damage that viruses can cause?", "choices": [{"text": "Computer slowdown", "correct": false}, {"text": "Corrupting files", "correct": false}, {"text": "Taking over basic functions of the operating system", "correct": false}, {"text": "Bandwidth consumption", "correct": true}]}, {"question": "Spyware is commonly used to bombard the user with:", "choices": [{"text": "Emails without attachments", "correct": false}, {"text": "Unsolicited text messages", "correct": false}, {"text": "Emails with attachments", "correct": false}, {"text": "Pop-up ads", "correct": true}]}, {"question": "Which of the following does the lesson NOT list as damage that Spyware can cause?", "choices": [{"text": "Crashing the computer", "correct": true}, {"text": "Collecting personal information", "correct": false}, {"text": "Installing unsolicited software", "correct": false}, {"text": "Redirecting web browsers", "correct": false}]}, {"question": "How do Trojans gain access to computers?", "choices": [{"text": "By being installed via a disk", "correct": false}, {"text": "By misleading the user of its true intention", "correct": true}, {"text": "By spreading via legitimate email attachments", "correct": false}, {"text": "None of the above", "correct": false}]}, {"question": "Which of the following does the lesson NOT list as damage that Trojans can cause?", "choices": [{"text": "Crashing the computer", "correct": false}, {"text": "Deleting files", "correct": false}, {"text": "Corrupting data", "correct": false}, {"text": "Redirecting web browsers", "correct": true}]}, {"question": "What do many employees at XYZ Company notice about their computers?", "choices": [{"text": "That they are running slowly", "correct": true}, {"text": "That they have crashed", "correct": false}, {"text": "That their files have become corrupt", "correct": false}, {"text": "That Safe Mode is no longer working", "correct": false}]}, {"question": "What does Harry say has happened to his computer?", "choices": [{"text": "Computer setting changes and web browser redirecting", "correct": true}, {"text": "Deleted files", "correct": false}, {"text": "Bandwidth consumption", "correct": false}, {"text": "Computer crashed", "correct": false}]}], "case_study": {"body": [], "video": "assets/videos/m03-types-of-malware-case-study.mp4", "poster": "assets/posters/m03-types-of-malware-case-study.jpg"}, "images": ["assets/images/m03-types-of-malware-hero.jpg"], "has_results": true}, {"number": 4, "name": "Cyber Security Breaches", "description": ["Cyber security breaches are the result of secure information being released to a treacherous environment. Whether the data is released intentionally or unintentionally, the consequences can have long-lasting effects, from harassment to identity theft."], "lessons": [{"title": "Phishing", "body": ["Cyber criminals who use phishing scams aim to obtain personal information by appearing to be a legitimate source. Many times, they masquerade as a major company, such as a bank, appealing to your desire to keep your information safe.\nFor example, they may send an email that says, \u201cWe suspect an unauthorized transaction on your account. To ensure that your account is not compromised, please click the link below and confirm your identity.\\\\"], "images": []}, {"title": "Identity Theft", "body": ["Identity theft can be considered one of the worst case scenarios when it comes to cyber security breaches. Whether hacking into a company\u2019s computer system to assume the identity of the computer or doing so to steal the identities of the company\u2019s customers / clients, the end result can be disastrous.\nThose who seek to steal another\u2019s identity typically do so and move on quickly, making it difficult to track and prosecute the perpetrator. This is why \u201can ounce of prevention is worth a pound of cure\u201d.\nThere are many ways to help prevent identity theft. Some examples are:\n\u00b7\tBe mindful of phishing websites\n\u00b7\tUtilize an Anti-virus / Anti-malware program\n\u00b7\tDon\u2019t respond to unsolicited requests for secure information"], "images": []}, {"title": "Harassment", "body": ["Cyber bullying is not just limited to individuals. Cyberbullies can use their vices to ruin the reputation of a company as well. Many companies have social media accounts that allow the general public to post comments, complaints, and suggestions. Some use this opportunity to post cruel and negative comments, or even threats.\nWhat are some ways to handle cyberbullies?\n\u00b7\tDo not immediately respond. When one feels attacked, the immediate tendency is to respond out of emotion. Doing so could escalate the issue, so take some time to process the information and compose yourself before dealing with the issue.\n\u00b7\tTell the cyberbully to stop. Granted, this may not always work, but sometimes being told that the behavior is not acceptable is all one needs in order to cease.\n\u00b7\tGet the authorities involved. Contact the police. The police many times have the necessary tools to track down the culprit and help put a stop to the behavior."], "images": []}, {"title": "Cyber Stalking", "body": ["Cyberstalking a company can include acts such as false accusations and defamation, which can affect the standing of the company in the community. The cyber stalkers\u2019 intention is typically to intimidate or in some way influence the victim. Cyberstalking is a criminal offense that is punishable under the anti-stalking laws.\nBeing found guilty of cyberstalking could lead to penalties from a restraining order against the assailant to the assailant serving jail time.\nAnti-Stalking Tips:\n\u00b7\tBe sure you always have physical access control over your computer, to prevent the stalker from gaining that control without your knowledge.\n\u00b7\tAlways log out of programs before stepping away from your desk. Utilize a screensaver and password.\n\u00b7\tProtect your passwords. Do not share them. Change them often.\n\u00b7\tKeep your security software updated."], "images": []}], "quizzes": [{"question": "How do phishing scam criminals attract their victims?", "choices": [{"text": "By appearing to be a legitimate source", "correct": true}, {"text": "By threatening them", "correct": false}, {"text": "Both of the above", "correct": false}, {"text": "None of the above", "correct": false}]}, {"question": "What is not one of the ways phishing uses individuals\u2019 information?", "choices": [{"text": "To obtain identifying information such as social security number, for malicious purposes", "correct": false}, {"text": "To commit crimes in the person\u2019s name", "correct": false}, {"text": "To steal banking details for personal gain", "correct": false}, {"text": "To keep the person\u2019s information safe", "correct": true}]}, {"question": "What quote is mentioned in the \u201cIdentity Theft\u201d lesson?", "choices": [{"text": "Identity theft is a serious crime that affects millions of Americans each year", "correct": false}, {"text": "I don\u2019t need to worry about identity theft because no one wants to be me", "correct": false}, {"text": "An ounce of prevention is worth a pound of cure", "correct": true}, {"text": "If we don\u2019t act now to safeguard our privacy, we could all become victims of identity theft", "correct": false}]}, {"question": "Of the following, which is not mentioned in the \u201cIdentity Theft\u201d lesson as a way to help prevent identity theft?", "choices": [{"text": "Be mindful of phishing websites", "correct": false}, {"text": "Protect your passwords", "correct": true}, {"text": "Utilize an Anti-Virus / Anti-Malware program", "correct": false}, {"text": "Don\u2019t respond to unsolicited requests for secure information", "correct": false}]}, {"question": "What is the first thing to do when you discover you have been a victim of cyber bullying?", "choices": [{"text": "Respond immediately", "correct": false}, {"text": "Compose yourself before responding", "correct": true}, {"text": "Call the police", "correct": false}, {"text": "Shut down your computer", "correct": false}]}, {"question": "What is a characteristic of cyber bullying?", "choices": [{"text": "Can affect companies as well as individuals", "correct": true}, {"text": "Is limited to adults", "correct": false}, {"text": "Is limited to teenagers", "correct": false}, {"text": "Only affects companies", "correct": false}]}, {"question": "What does the lesson mention on how cyberstalking is punishable?", "choices": [{"text": "Monetary penalties only", "correct": false}, {"text": "Monetary penalties and jail time", "correct": false}, {"text": "Restraining order and monetary penalties", "correct": false}, {"text": "Restraining order and jail time", "correct": true}]}, {"question": "What is not mentioned in the \u201cCyberstalking\u201d lesson as an anti-stalking tip?", "choices": [{"text": "Log out of programs before stepping away from your desk", "correct": false}, {"text": "Do not leave on your computer through the night", "correct": true}, {"text": "Protect passwords", "correct": false}, {"text": "Keep security software updated", "correct": false}]}, {"question": "Receiving an email that says, \u201cWe suspect an unauthorized transaction on your account. To ensure that your account is not compromised, please click the link below and confirm your identity\u201d, is MOST likely characteristic of what?", "choices": [{"text": "Cyber bullying", "correct": false}, {"text": "Cyber stalking", "correct": false}, {"text": "Harassment", "correct": false}, {"text": "Phishing", "correct": true}]}, {"question": "What does Emily tell Paula about the email she received?", "choices": [{"text": "Their company does that all of the time and she should click the link", "correct": false}, {"text": "Their company does that sometimes, but she should confirm with their supervisor", "correct": false}, {"text": "Their company doesn\u2019t do that, and most companies don\u2019t", "correct": true}, {"text": "She is not sure what Paula should do", "correct": false}]}], "case_study": {"body": [], "video": "assets/videos/m04-cyber-security-breaches-case-study.mp4", "poster": "assets/posters/m04-cyber-security-breaches-case-study.jpg"}, "images": ["assets/images/m04-cyber-security-breaches-hero.jpg"], "has_results": true}, {"number": 5, "name": "Types of Cyber Attacks", "description": ["Cyber attacks are orchestrated by individuals or groups to destroy the information systems, networks, etc. of others. From installing Spyware on a computer to obliterating a company\u2019s entire infrastructure, cyber-attacks can have devastating effects on many."], "lessons": [{"title": "Password Attacks", "body": ["Passwords are intended to prevent unauthorized access to your accounts, so it\u2019s important to use passwords that are strong in order to prevent threats against the privacy and security of the data associated with your company and customers.\nWhy is it important to use a strong password?\nThere is software available to hackers that will allow them to try various passwords in an attempt crack the code of and infiltrate your system.\nHow to protect your business:\n\u00b7\tCreate a password that is easy for you to remember but difficult for someone else to figure out\n\u00b7\tInclude upper and lower case letters, numbers, and symbols\n\u00b7\tCraft a password that is long\n\u00b7\tRegularly update your password"], "images": []}, {"title": "Denial of Service Attacks", "body": ["Denial of service attacks are just as its name states. Its goal is to make a network unavailable to its intended users. This type of attack can be used against individuals where they consecutively enter the wrong password enough times that they are locked out of their account. It can also manifest as a network being so overloaded that no one can get in.\nDamage caused by denial of service attacks:\n\u00b7\tNetwork performs slowly\n\u00b7\tA specific website is inaccessible\n\u00b7\tNo websites are accessible\n\u00b7\tReceiving a large amount of spam emails"], "images": []}, {"title": "Passive Attack", "body": ["A passive attack is conducted to simply find the vulnerabilities of system, but not change any data at that time. Think of it in terms of a conversation that two people are having and the passive attacker is eavesdropping in on the conversation. Although it may seem like a harmless act at the time, if the intruder is able to obtain the \u201cright\u201d information, he/she can use that in the future to cause irreparable damage.\nA passive attack is different from an active attack, which aims to change data of the system at the time of the attack."], "images": []}, {"title": "Penetration Testing", "body": ["Penetration testing can be a positive tool for an organization. It is done to unearth the vulnerabilities of a computer system, then take advantage of those vulnerabilities to get an idea of the impact an actual attack will have on the system.\nThere are many reasons why a company would utilize penetration testing. Some of these include:\n\u00b7\tEstablish the likelihood of a specific attack occurring\n\u00b7\tDetect high risk vulnerabilities that can result from a grouping of low risk vulnerabilities that take place in a particular pattern\n\u00b7\tDetermine the bearing an attack will have on a company\n\u00b7\tAssess the company\u2019s network risk management capabilities"], "images": []}], "quizzes": [{"question": "You should create a password that is:", "choices": [{"text": "Easy for you to remember and easy for others to figure out", "correct": false}, {"text": "Difficult for you to remember but easy for others to figure out", "correct": false}, {"text": "Easy for you to remember but difficult for others to figure out", "correct": true}, {"text": "Difficult for you to remember and difficult for others to figure out", "correct": false}]}, {"question": "What should your password include?", "choices": [{"text": "Upper and lower case letters", "correct": false}, {"text": "Upper and lower case letters, numbers, and symbols", "correct": true}, {"text": "Numbers and symbols", "correct": false}, {"text": "Upper case letters, numbers, and symbols", "correct": false}]}, {"question": "What is a denial of service attack?", "choices": [{"text": "An attack that prevents unintended users from being able to access a network", "correct": false}, {"text": "An attack that prevents users from being able to access a network in the early morning hours only", "correct": false}, {"text": "An attack that prevents users from being able to access a network in the late night hours only", "correct": false}, {"text": "An attack that prevents intended users from being able to access a network", "correct": true}]}, {"question": "Which of the following is not mentioned in the \u201cDenial of Service Attack\u201d lesson as damage that denial of service attacks can cause?", "choices": [{"text": "Network performs slowly", "correct": false}, {"text": "A particular website is inaccessible", "correct": false}, {"text": "Receiving a large amount of spam emails", "correct": false}, {"text": "None of the above", "correct": true}]}, {"question": "What is the purpose of a passive attack?", "choices": [{"text": "To find network vulnerabilities and immediately change data", "correct": false}, {"text": "To warn the network user of an impending active attack", "correct": false}, {"text": "To find network vulnerabilities but not change data at the time", "correct": true}, {"text": "To warn the network user of vulnerabilities so the user can fix them", "correct": false}]}, {"question": "In the lesson, passive attacks are likened to:", "choices": [{"text": "Eavesdropping", "correct": true}, {"text": "Murder", "correct": false}, {"text": "Downloading", "correct": false}, {"text": "Overloading", "correct": false}]}, {"question": "What is penetration testing used for?", "choices": [{"text": "In a controlled environment, to find vulnerabilities in the network, but not exploit them", "correct": false}, {"text": "In a controlled environment, to find vulnerabilities in the network and exploit those vulnerabilities to see what impact an actual attack would have", "correct": true}, {"text": "In an uncontrolled environment, to find vulnerabilities in the network and exploit those vulnerabilities to see what impact an actual attack would have", "correct": false}, {"text": "In an uncontrolled environment, to find vulnerabilities in the network, but not exploit them", "correct": false}]}, {"question": "Which of these is discussed in the \u201cPenetration Testing\u201d lesson as a reason that companies implement such testing?", "choices": [{"text": "Establish the likelihood of a specific attack occurring", "correct": false}, {"text": "Detect high risk vulnerabilities that can result from a grouping of low risk vulnerabilities that take place in a particular pattern", "correct": false}, {"text": "Determine the bearing an attack will have on a company", "correct": false}, {"text": "All of the above", "correct": true}]}, {"question": "Kurt\u2019s password will consist of:", "choices": [{"text": "Numbers, letters, and symbols", "correct": true}, {"text": "Numbers only", "correct": false}, {"text": "Letters only", "correct": false}, {"text": "Symbols only", "correct": false}]}, {"question": "Receiving a large amount of spam mail and being locked out of the system after putting in the correct password, but not given access are characteristic of which of the following?", "choices": [{"text": "Password attack", "correct": false}, {"text": "Denial of service", "correct": false}, {"text": "Denial of service and password attack", "correct": true}, {"text": "None of the above", "correct": false}]}], "case_study": {"body": [], "video": "assets/videos/m05-types-of-cyber-attacks-case-study.mp4", "poster": "assets/posters/m05-types-of-cyber-attacks-case-study.jpg"}, "images": ["assets/images/m05-types-of-cyber-attacks-hero.png"], "has_results": true}, {"number": 6, "name": "Prevention Tips", "description": ["Although it may not be possible to completely avoid falling victim to cybercrime, having a tool kit of prevention methods could help your organization minimize the risk of such crimes damaging the reputation of your company or faith of your clients/customers."], "lessons": [{"title": "Craft a Strong Password", "body": ["One of the easiest steps to keeping your data safe is to craft solid login credentials. If possible, remember the password so that it doesn\u2019t have to be written down. If you must have the password written down on hard copy somewhere, be sure to store it in a secure location, with few people who have access to it.\nWhat are some tips for creating a strong password?\n1.\tUse a unique password for each of your accounts. Do not use one password for all of them.\n2.\tEnsure your password consists of letters, numbers, and symbols. This would make it harder for others to figure out.\n3.\tAvoid using common words or consecutive characters to make up your password (e.g. Do not use \u201cpassword\u201d as your password. Do not use a password such as Office111)."], "images": []}, {"title": "Two-Step Verification", "body": ["Two-Step Verification is a way of authenticating and individual\u2019s identity using two components, before he/she gains access.\nThe idea behind this process is that although an imposter has one piece of the victim\u2019s identifying information, they most likely don\u2019t have two.\nExamples of information that may be used for authentication purposes:\n\u00b7\tToken\n\u00b7\tKey\n\u00b7\tPassword\n\u00b7\tPin\n\u00b7\tFingerprint\n\u00b7\tVoice recognition"], "images": []}, {"title": "Download Attachments with Care", "body": ["It\u2019s important to always download email attachments with care, even if the email appears to be from a credible source. Although the attachment seems to have a well-known extension (e.g. .PDF, .doc, etc.), it could in fact be a Trojan.\nProtect yourself by considering these steps:\n\u00b7\tRegularly update software patches.\n\u00b7\t\u201cGo with your gut\u201d. If something doesn\u2019t seem right, it probably isn\u2019t.\n\u00b7\tSave and scan the true source of the attachment before opening it."], "images": []}, {"title": "Question Legitimacy of Websites", "body": ["There are many websites that at first glance, look like legitimate sites. But, upon further examination, you realize it is a spoof. Opening such a site could lead to damage such as slowing down the speed of your computer or even worse, the loss of files or stolen identity. It is important to take precautionary measures when visiting websites, even if it is a site you have visited in the past.\n\u00b7\tType the complete URL in the browser\n\u00b7\tWhen doing a Google/Bing search, do not open websites with names that just don\u2019t look right\n\u00b7\tQuestion the intentions of the sender when you receive an unsolicited email to visit a particular website\n\u00b7\tMake sure your Anti-Spyware/Anti-Virus program is up-to-date so it can warn you of a website that looks suspicious"], "images": []}], "quizzes": [{"question": "What is the best way to store a password?", "choices": [{"text": "On a sticky note on your desk", "correct": false}, {"text": "In your memory", "correct": true}, {"text": "In your phone", "correct": false}, {"text": "In a notebook located in an unlocked desk", "correct": false}]}, {"question": "When is it best to use one password for all of your accounts?", "choices": [{"text": "If you have no more than two accounts", "correct": false}, {"text": "If you have no more than three accounts", "correct": false}, {"text": "Never", "correct": true}, {"text": "If you have no more than four accounts", "correct": false}]}, {"question": "In the \u201cTwo-Step Verification\u201d lesson, which of these is mentioned as something that may be used for authentication purposes?", "choices": [{"text": "Token", "correct": false}, {"text": "Key", "correct": false}, {"text": "Password", "correct": false}, {"text": "All of the above", "correct": true}]}, {"question": "The \u201cTwo-Step Verification\u201d lesson states that which of these can be used to confirm an individual\u2019s identity?", "choices": [{"text": "Pin", "correct": false}, {"text": "Fingerprint", "correct": false}, {"text": "Voice recognition", "correct": false}, {"text": "All of the above", "correct": true}]}, {"question": "What is true of an email attachment with an extension of .doc?", "choices": [{"text": "It could be a Trojan", "correct": true}, {"text": "It should never be downloaded", "correct": false}, {"text": "It will always be a legitimate attachment", "correct": false}, {"text": "It should only be downloaded if it is sent from a co-worker", "correct": false}]}, {"question": "What is a way to protect yourself when it comes to opening attachments?", "choices": [{"text": "Regularly update software patches", "correct": false}, {"text": "Go with your gut", "correct": false}, {"text": "Save and scan the true sender of the attachment", "correct": false}, {"text": "All of the above", "correct": true}]}, {"question": "Opening a website that appears to be legitimate but is a spoof can do all of the following, except:", "choices": [{"text": "Slow down the speed of your computer", "correct": false}, {"text": "Cause a loss of files", "correct": false}, {"text": "Increase the speed of your computer", "correct": true}, {"text": "Cause a stolen identity", "correct": false}]}, {"question": "Which of these is not mentioned as a precautionary measure to avoid opening a spoof website?", "choices": [{"text": "Type the complete URL in the browser", "correct": false}, {"text": "Question the intention of the sender of an unsolicited request to visit a website", "correct": false}, {"text": "Ensure your Anti-Virus / Anti-Spyware is up-to-date", "correct": false}, {"text": "Visit the website from at least two different computers to make sure it is legitimate", "correct": true}]}, {"question": "What does Ann tell the trainees about why the company has a two-step verification process?", "choices": [{"text": "Because the federal law requires it", "correct": false}, {"text": "Because the state law requires it", "correct": false}, {"text": "So that only the authorized user can access the account", "correct": true}, {"text": "So they can weed out the employees who are not serious about computer security", "correct": false}]}, {"question": "Who asks about the company\u2019s policy on opening email attachments?", "choices": [{"text": "Carl", "correct": true}, {"text": "Ann", "correct": false}, {"text": "An unnamed trainee", "correct": false}, {"text": "Sybil", "correct": false}]}], "case_study": {"body": [], "video": "assets/videos/m06-prevention-tips-case-study.mp4", "poster": "assets/posters/m06-prevention-tips-case-study.jpg"}, "images": ["assets/images/m06-prevention-tips-hero.png"], "has_results": true}, {"number": 7, "name": "Mobile Protection", "description": ["It is just as important to protect your Smartphone as it is your computer. With phones having many of the same capabilities as computers, they are open to many of the same vulnerabilities that computers face. This module will discuss several small but effective steps to take to ensure mobile protection."], "lessons": [{"title": "No Credit Card Numbers", "body": ["Many times, it seems convenient to store credit card numbers on your phone so you have them at your fingertips and you don\u2019t necessarily have to rely on your memory. But, just as it is easy for you to access these numbers, it is easy for someone who means harm to access them.\nIf for some reason it is absolutely necessary for you to store this information on your phone, it is important for you to take extreme measures to make sure the data is safeguarded, such as token-ization and/or encryption."], "images": []}, {"title": "Place Lock on Phone", "body": ["Enabling a lock on your phone when not in use, and a pin or password to unlock the phone could help prevent unauthorized use of the phone. Just as we talked about in a previous module, if you set a password on your phone, it is important to create a strong password.\nAs a reminder, keep these tips in mind when creating your password:\n\u00b7\tUse a unique password for each of your accounts. Do not use one password for all of them.\n\u00b7\tEnsure your password consists of letters, numbers, and symbols. This would make it harder for others to figure out.\n\u00b7\tAvoid using common words or consecutive characters to make up your password (e.g. Do not use \u201cpassword\u201d as your password. Do not use a password such as Office111)."], "images": []}, {"title": "Don\u2019t Save Passwords", "body": ["When it comes to passwords, the ideal situation would be to remember them so there is no trail of what they are, which could make it easy for an unauthorized user to utilize them. But the fact is, most people have unique passwords for each account they have. Because of this, it may be necessary to use a back-up method in case they are forgotten. If this is the case, write them down and securely store them. Do not save them on your phone.\n\u00b7\tWrite them down and treat them as you would any other important documents by locking them in a safe or drawer that requires a key.\n\u00b7\tInvest in a password manager service."], "images": []}, {"title": "No Personalized Contacts Listed", "body": ["You\u2019ve created a lock on your phone and regularly lock it when it\u2019s not in use. You quickly step away from your desk with your phone on it, and forget to lock it. Someone who doesn\u2019t have permission to touch your phone decides to go through your contact list. John sees the name Bob Jones with \u201cABC Company Manager\u201d in parentheses. John writes down Bob\u2019s name and number and decides to use it to solicit Bob\u2019s business.\n\nThis is one scenario of what can happen when your phone includes a personalized contact list. In this example, the result, while uncomfortable, is not an extreme situation. Just think what could have happened!"], "images": []}], "quizzes": [{"question": "Credit card numbers:", "choices": [{"text": "Should only be stored in your phone if you have less than three credit cards", "correct": false}, {"text": "Should only be stored in your phone if you have less than two credit cards", "correct": false}, {"text": "Should always be stored in your phone", "correct": false}, {"text": "Should not be stored in your phone, if possible", "correct": true}]}, {"question": "What is a way to safeguard credit card information that you must store on your phone?", "choices": [{"text": "Encryption", "correct": false}, {"text": "Token-ization", "correct": false}, {"text": "Both of the above", "correct": true}, {"text": "None of the above", "correct": false}]}, {"question": "When setting up a lock on your phone that can be opened with a password:", "choices": [{"text": "Use a password that is the same as all of your other passwords", "correct": false}, {"text": "Use a password that is different from all of your other passwords", "correct": true}, {"text": "Use a password that has no more than five characters", "correct": false}, {"text": "Use a password that has no more than three characters", "correct": false}]}, {"question": "To create a strong password, it should have:", "choices": [{"text": "Letters and numbers", "correct": false}, {"text": "Numbers and symbols", "correct": false}, {"text": "Letters, numbers, and symbols", "correct": true}, {"text": "Letters and symbols", "correct": false}]}, {"question": "What should be your back-up method if you cannot remember your password?", "choices": [{"text": "Write down and place in a secure location", "correct": true}, {"text": "Save it on your phone", "correct": false}, {"text": "Write it down and leave it with a person you trust", "correct": false}, {"text": "All of the above", "correct": false}]}, {"question": "The \u201cDon\u2019t Save Passwords\u201d lesson states that passwords should be secured where?", "choices": [{"text": "In a co-worker\u2019s files", "correct": false}, {"text": "On the main screen of your phone", "correct": false}, {"text": "In a closet", "correct": false}, {"text": "In a safe", "correct": true}]}, {"question": "What is the name of the person in the contact list?", "choices": [{"text": "Bill Johnson", "correct": false}, {"text": "John Taylor", "correct": false}, {"text": "Jim Smith", "correct": false}, {"text": "Bob Jones", "correct": true}]}, {"question": "What was the job title of the person in the contact list?", "choices": [{"text": "Quality representative", "correct": false}, {"text": "Manager", "correct": true}, {"text": "Account manager", "correct": false}, {"text": "Client relations representative", "correct": false}]}, {"question": "What does Delores want to save on her phone?", "choices": [{"text": "Customers\u2019 credit card information", "correct": true}, {"text": "Passwords for her social media accounts", "correct": false}, {"text": "Her boss\u2019 birthday", "correct": false}, {"text": "The address to a client\u2019s office", "correct": false}]}, {"question": "What does Delores and Earl\u2019s manager encourage them to do?", "choices": [{"text": "Recharge their phones every three hours", "correct": false}, {"text": "Only use their phones after 2:00 p.m.", "correct": false}, {"text": "Save customers\u2019 credit card information on their phones", "correct": false}, {"text": "Lock their phones when they\u2019re not in use", "correct": true}]}], "case_study": {"body": [], "video": "assets/videos/m07-mobile-protection-case-study.mp4", "poster": "assets/posters/m07-mobile-protection-case-study.jpg"}, "images": ["assets/images/m07-mobile-protection-hero.png"], "has_results": true}, {"number": 8, "name": "Social Network Security", "description": ["Many people forget that with social networking, although they are not meeting with people face-to-face, revealing too much information about oneself could still lead to dangerous situations, such as social engineering attacks. This module will discuss some of the ways to protect yourself from being lulled into a false sense of security."], "lessons": [{"title": "Don\u2019t Reveal Location", "body": ["This seems like an issue of common sense, but many need to be reminded that revealing your location to strangers is never a good idea. Some social media sites require that you input your location, and if that\u2019s the case, you can use your creativity to make a fake location or input one a city/state different from where you are actually located. In some instances, the website will allow you to continue without entering anything in the location field.\n\nThe Internet is a public source and with disclosing your actual location to strangers, you could open yourself to crimes such as burglary, harassment, or stalking ."], "images": []}, {"title": "Keep Birthdate Hidden", "body": ["Giving away your birthdate seems like a harmless act, but when a criminal has your birthday, they have one of the several pieces of information needed to steal your identity. If you absolutely must list your birthdate, do not include the year."], "images": []}, {"title": "Have Private Profile", "body": ["Just because you post something, doesn\u2019t mean it\u2019s for everybody to see. Although social media is a useful way of networking professionally and promoting your business, failing to properly manage your profile and privacy settings could have consequences that you cannot undo.\nEach social media platform has its own instructions for updating the settings of your profile so that information is distributed according to your wishes. Be sure to thoroughly read through these guidelines.\n\nSome of the most common social media websites:\n\u00b7\tFacebook\n\u00b7\tInstagram\n\u00b7\tTwitter\n\u00b7\tGoogle+\n\u00b7\tLinkedIn\n\u00b7\tPinterest"], "images": []}, {"title": "Don\u2019t Link Accounts", "body": ["Although linking social media accounts may be a convenience to you, it is making it easier for thieves to find you. It is especially important that you don\u2019t link your personal accounts with your business accounts. Some content on one of your social media sites may not be appropriate for content on another site. For example content you post on Facebook, which is a relatively informal site, may not be appropriate for your LinkedIn account, which is a more formal setting.\nWhat are some other reasons why you shouldn\u2019t link your social media accounts?\n\u00b7\tAutomated posting\n\u00b7\tSame messages across different platforms\n\u00b7\tIncreased risk of identity theft\n\u00b7\tMore of a chance of receiving spam in inbox (which can be malware and/or viruses)"], "images": []}], "quizzes": [{"question": "What is the MOST effective thing to do if a social media site requires you to put in your address?", "choices": [{"text": "Put in your actual location", "correct": false}, {"text": "Put in a fake address", "correct": true}, {"text": "Contact customer service and complain", "correct": false}, {"text": "Refuse to open an account", "correct": false}]}, {"question": "Which of these is NOT mentioned in the \u201cDon\u2019t Reveal Location\u201d lesson of potential things that can happen as a result of inputting your real location?", "choices": [{"text": "Burglary", "correct": false}, {"text": "Harassment", "correct": false}, {"text": "Stalking", "correct": false}, {"text": "Stolen identity", "correct": true}]}, {"question": "If your birthday is visible on your account, what part of it should you not include?", "choices": [{"text": "Month", "correct": false}, {"text": "Day", "correct": false}, {"text": "Year", "correct": true}, {"text": "Day of the week you were born", "correct": false}]}, {"question": "The first sentence of the \u201cKeep Birthdate Hidden\u201d lesson says, \u201cGiving away your birthday seems like a ______ act...\u201d", "choices": [{"text": "Harmless", "correct": true}, {"text": "Wise", "correct": false}, {"text": "Foolish", "correct": false}, {"text": "Noble", "correct": false}]}, {"question": "Which of these is NOT mentioned in \u201cHave Private Profile\u201d as one of the common social media platforms used?", "choices": [{"text": "Facebook", "correct": false}, {"text": "YouTube", "correct": true}, {"text": "Instagram", "correct": false}, {"text": "Twitter", "correct": false}]}, {"question": "Of the following, which is NOT listed in \u201cHave Private Profile\u201d as a common social media website?", "choices": [{"text": "Google+", "correct": false}, {"text": "LinkedIn", "correct": false}, {"text": "Flickr", "correct": true}, {"text": "Pinterest", "correct": false}]}, {"question": "You should:", "choices": [{"text": "Always link your business and personal accounts", "correct": false}, {"text": "Never link your business and personal accounts", "correct": true}, {"text": "Only link your business and personal accounts if you have only one of each", "correct": false}, {"text": "Only link your business and personal accounts if you have less than three of each", "correct": false}]}, {"question": "Which of these is NOT listed as a reason to not link your social media accounts?", "choices": [{"text": "Decreased risk of identity theft", "correct": true}, {"text": "Automated posting", "correct": false}, {"text": "Same messages across different platforms", "correct": false}, {"text": "Increased risk of identity theft", "correct": false}]}, {"question": "Who wants to link their personal and business social media accounts?", "choices": [{"text": "Talent", "correct": false}, {"text": "Reagan", "correct": true}, {"text": "Both Reagan and Isabel", "correct": false}, {"text": "Neither Reagan nor Isabel", "correct": false}]}, {"question": "Who is responsible for setting up and managing the candy shop\u2019s social media account?", "choices": [{"text": "Isabel", "correct": false}, {"text": "Reagan", "correct": true}, {"text": "Both Reagan and Isabel", "correct": false}, {"text": "Neither Reagan for Isabel", "correct": false}]}], "case_study": {"body": [], "video": "assets/videos/m08-social-network-security-case-study.mp4", "poster": "assets/posters/m08-social-network-security-case-study.jpg"}, "images": ["assets/images/m08-social-network-security-hero.png"], "has_results": true}, {"number": 9, "name": "Prevention Software", "description": ["Now we\u2019ve gotten to the good stuff! We\u2019ve thoroughly covered the many dangers lurking, with the hopes of taking over your computer systems and even steal your identity. It\u2019s now time to talk about the proactive steps you can take to protect yourself and your business. While you may not be able to completely avoid these risks, there are many ways to lessen your exposure to threats, vulnerabilities, and attacks."], "lessons": [{"title": "Firewalls", "body": ["Firewalls use pre-set security rules to keep track of and regulate the incoming and outgoing traffic of your network system.\n\nThink of a fire wall as a blockade between the internal network, which is a trusted source, and external networks which are presumed to not be safe.\n\nThe two types of firewalls are network firewalls and host-based firewalls. Network firewalls specifically filter the flow of traffic concerning at least two networks, while host-based firewalls deal with one host that manages the traffic in and out of that particular machine."], "images": []}, {"title": "Virtual Private Networks", "body": ["Virtual private networks (VPNs) are private networks that spread across a public network (the Internet). VPNs enable users to send and receive information across the public network as if they are connected to the private networks.An example of this would be a company that gives its employees access to its Intranet while not inside of the office. This would be called Remote Access VPN.\nAnother type of VPN is Site-to-Site VPN. This is where one company has offices in different geographical locations. Users are able to connect the network of one office site to the network of another office site.\nThe above VPN types are based on a variety of VPN security protocols, which come with different qualities and degree of security.\nProtocols:\n\u00b7\tInternet Protocol Security\n\u00b7\tLayer 2 Tunneling Protocol\n\u00b7\tPoint-to-Point Tunneling Protocol\n\u00b7\tSecure Sockets Layer and Transport Layer Security\n\u00b7\tOpenVPN\n\u00b7\tSecure Shell"], "images": []}, {"title": "Anti-Virus & Anti-Spyware", "body": ["Anti-Virus Software\nAnti-Virus Software protects users from many different threats. Some of these include viruses, browser hijackers, rootkits, Trojans, worms, and Ransomware.\n\nAnti-Spyware Software\nAnti-Spyware Software aims to detect and dispose of spyware programs that the user doesn\u2019t intend to have on his system. These Spyware programs are installed on the computer without the user\u2019s knowledge or consent and collects information about them. Spyware can cause damage such as posing a security risk and reducing system performance.\n\nExamples of companies that offer Anti-Virus/ Anti-Spyware programs:\n\u00b7\tMcAfee\n\u00b7\tKaspersky\n\u00b7\tBitdefender\n\u00b7\tNorton\nTo ensure you Anti-Virus/ Anti-Spyware programs are working properly, it is crucial that you regularly update your settings and run scheduled scans to check for anything suspicious."], "images": []}, {"title": "Routine Updates", "body": ["Operating systems regularly release updates to address security issues and improve computer performance. The three categories that these fall into are high priority, suggested, and drivers.\nHigh priority updates are just as their name states. They are very important and should be non-negotiable. Examples of such updates include security patches and bug fixes.\nSuggested updates can help improve the performance of your computer, but not typically do not allow for major problems, if not installed.\nDrivers can be a bit more complicated if you\u2019re not versed in what they are and how to install them. If you are positive that you need the update for that driver, install it. Otherwise, it could be more of a headache than it is worth."], "images": []}], "quizzes": [{"question": "Which of the following are two types of firewalls?", "choices": [{"text": "Network and host-based", "correct": true}, {"text": "Anti-Virus and Anti-Spyware", "correct": false}, {"text": "Network and Internet", "correct": false}, {"text": "Host-based and Intranet", "correct": false}]}, {"question": "What are firewalls designed to do?", "choices": [{"text": "Keep track of but not regulate incoming and outgoing traffic of your network system", "correct": false}, {"text": "Keep track of incoming traffic of your network system", "correct": false}, {"text": "Keep track of and regulate incoming and outgoing traffic of your network system", "correct": true}, {"text": "Keep track of outgoing traffic of your network system", "correct": false}]}, {"question": "An example of using a VPN is a company that gives its employees access to its Intranet while not inside of the office. What type of VPN is this?", "choices": [{"text": "Site-to-site", "correct": false}, {"text": "Remote access", "correct": true}, {"text": "Public access", "correct": false}, {"text": "Telecommute", "correct": false}]}, {"question": "Of the following, which is an actual VPN protocol?", "choices": [{"text": "Internet Protocol Security", "correct": false}, {"text": "Layer 2 Tunneling", "correct": false}, {"text": "Point-to-Point Tunneling", "correct": false}, {"text": "All of the above", "correct": true}]}, {"question": "What are threats that Anti-Virus software protects against?", "choices": [{"text": "Trojans", "correct": false}, {"text": "Viruses", "correct": false}, {"text": "Browser hijackers", "correct": false}, {"text": "All of the above", "correct": true}]}, {"question": "Which of these companies offers Anti-Virus and Anti-Spyware software?", "choices": [{"text": "McAfee", "correct": false}, {"text": "Norton", "correct": false}, {"text": "Kaspersky", "correct": false}, {"text": "All of the above", "correct": true}]}, {"question": "Which of these is typically the MOST complicated update to install?", "choices": [{"text": "High priority", "correct": false}, {"text": "Suggested", "correct": false}, {"text": "Drivers", "correct": true}, {"text": "None of the above", "correct": false}]}, {"question": "How often do operating systems release updates?", "choices": [{"text": "Regularly", "correct": true}, {"text": "Once every year", "correct": false}, {"text": "Once every two years", "correct": false}, {"text": "Once every three years", "correct": false}]}, {"question": "Greg says at a minimum, they should invest in:", "choices": [{"text": "Making sure their operating system performs its routine updates", "correct": false}, {"text": "Firewalls", "correct": false}, {"text": "Anti-Virus and Anti-Spyware software", "correct": true}, {"text": "VPNs", "correct": false}]}, {"question": "What is Greg concerned about?", "choices": [{"text": "What security will be in place when they are on vacation?", "correct": false}, {"text": "What security will be in place when they are working away from the office?", "correct": true}, {"text": "What security will be in place through the night?", "correct": false}, {"text": "What security will be in place on weekends?", "correct": false}]}], "case_study": {"body": [], "video": "assets/videos/m09-prevention-software-case-study.mp4", "poster": "assets/posters/m09-prevention-software-case-study.jpg"}, "images": ["assets/images/m09-prevention-software-hero.png"], "has_results": true}, {"number": 10, "name": "Critical Cyber Threats", "description": ["Critical cyber threats are those that if carried out, could have a debilitating effect on an organization or even a country. In the case of a country, it could negatively impact aspects such as security, national economic security, and national public health."], "lessons": [{"title": "Critical Cyber Threats", "body": ["As mentioned above, these cyber threats are not designed to temporarily disable an organization, but completely destroy it. To give you an idea of the magnitude of such an attack, again using a country as an example, according to the Department of Homeland Security, some of the critical infrastructures of a country that can be demolished as a result include:\nSource: www.grist.org\n\u00b7\tEnergy\n\u00b7\tDefense\n\u00b7\tTransportation\n\u00b7\tFood and agriculture\n\u00b7\tEmergency services\n\u00b7\tCommunications\n\u00b7\tWater and wastewater", "\u00b7\tManufacturing\n\u00b7\tChemical\n\u00b7\tCommercial facilities\n\u00b7\tDams\n\u00b7\tFinance\n\u00b7\tHealthcare\n\u00b7\tGovernment facilities\n\u00b7\tNuclear facilities"], "images": []}, {"title": "Cyber Terrorism", "body": ["Cyber Terrorism is cyber threats/attacks on a large scale. These acts are designed to terrorize the Internet as a whole or entire computer networks. This is done by tools such as spreading viruses to computers.\nExamples of cyberterrorism include:\n\u00b7\tIn 1996, a computer hacker allegedly associated with the White Supremacist movement temporarily disabled a Massachusetts ISP and damaged part of the ISP's record keeping system. The ISP had attempted to stop the hacker from sending out worldwide racist messages under the ISP's name. The hacker signed off with the threat, \\\\"], "images": []}, {"title": "Cyber Warfare", "body": ["Cyber warfare is a means of war against another state or country to damage that other state/country\u2019s information networks. Many times this is carried out via computer viruses or denial of service attacks.\nExamples of cyber warfare include:\n\u00b7\tIn 1998, the United States hacked into Serbia's air defense system to compromise air traffic control and facilitate the bombing of Serbian targets.\n\u00b7\tIn 2007, in Estonia, a botnet <http://searchsecurity.techtarget.com/definition/botnet> of over a million computers brought down government, business and media websites across the country. The attack was suspected to have originated in Russia, motivated by political tension between the two countries.\n\n\u00b7\tIn 2009, a cyber spy network called \\\\"], "images": []}, {"title": "Cyber Espionage", "body": ["The purpose of cyber espionage is to obtain the secrets of another, without their permission. The perpetrator of the espionage is typically trying to acquire sensitive, proprietary, or classified information. This can be committed against anyone from an individual to a company to a country. The information will be used as an advantage against the one from whom the information was stolen. It can be accomplished through means such as cracking, Trojans, and the installation of Spyware.\nExamples of cyber espionage include:\n\u00b7\tThe Wall Street Journal reported that unnamed government officials told the Wall Street Journal that cyberspies from China and Russia had broken into computer systems used by companies maintaining the three North American electrical grids.\n\u00b7\tCanadian researchers revealed in late March that a cyber-spy network based in China had broken into diplomatic computer systems involving 103 different countries. Beijing denied any official involvement, but the investigation had begun when the Dalai Lama, Tibet's leader-in-exile, noticed that sensitive documents from his own PCs had turned up in Chinese hands.\n\nSource: http://www.foxnews.com/story/2009/04/22/five-serious-cases-cyberespionage.html"], "images": []}], "quizzes": [{"question": "According to the \u201cCritical Cyber Threats\u201d lesson, which of these is mentioned as a critical infrastructure?", "choices": [{"text": "Energy", "correct": false}, {"text": "Defense", "correct": false}, {"text": "Transportation", "correct": false}, {"text": "All of the above", "correct": true}]}, {"question": "Which of the following is NOT listed in \u201cCritical Cyber Threats\u201d as a type of critical infrastructure?", "choices": [{"text": "Food and agriculture", "correct": false}, {"text": "Emergency services", "correct": false}, {"text": "Communications", "correct": false}, {"text": "None of the above", "correct": true}]}, {"question": "In the white supremacist example of Cyber terrorism, what state\u2019s ISP was temporarily disabled?", "choices": [{"text": "Oregon", "correct": false}, {"text": "Massachusetts", "correct": true}, {"text": "Alabama", "correct": false}, {"text": "New Mexico", "correct": false}]}, {"question": "In the Institute for Global Communications Cyber terrorism example, protesters from what country bombarded the institute with thousands of bogus e-mails?", "choices": [{"text": "Spain", "correct": true}, {"text": "France", "correct": false}, {"text": "Nigeria", "correct": false}, {"text": "China", "correct": false}]}, {"question": "In the Cyber warfare examples, in 1998, the United States hacked into what country\u2019s air defense system?", "choices": [{"text": "North Korea", "correct": false}, {"text": "Russia", "correct": false}, {"text": "Serbia", "correct": true}, {"text": "Germany", "correct": false}]}, {"question": "In 2009, a cyber spy network called ______ accessed confidential information belonging to both governmental and private organizations.", "choices": [{"text": "GhostNet", "correct": true}, {"text": "Internet Spy", "correct": false}, {"text": "CyberNet", "correct": false}, {"text": "Ghost Town", "correct": false}]}, {"question": "In one of the examples in the \u201cCyber espionage\u201d lesson, an unnamed government official told the Wall Street Journal that cyber spies from which countries had broken into computer systems?", "choices": [{"text": "Israel and Italy", "correct": false}, {"text": "Japan and India", "correct": false}, {"text": "Poland and Scotland", "correct": false}, {"text": "China and Russia", "correct": true}]}, {"question": "Canadian researchers revealed in late March that a cyber-spy network based in what country had broken into diplomatic computer systems involving 103 different countries?", "choices": [{"text": "China", "correct": true}, {"text": "Ireland", "correct": false}, {"text": "Turkey", "correct": false}, {"text": "Iraq", "correct": false}]}, {"question": "In the case study, what\u2019s the name of the business that is receiving threats?", "choices": [{"text": "Larry\u2019s Tire and Lube", "correct": false}, {"text": "Lucy\u2019s Malt Shop", "correct": false}, {"text": "Lucky\u2019s Cleaners", "correct": true}, {"text": "Linda\u2019s Computer Repair", "correct": false}]}, {"question": "What is Martha concerned about?", "choices": [{"text": "That its competitor will bad mouth her business to prospective clients", "correct": false}, {"text": "That its competitor will bad mouth her business to prospective clients and try to disable its computer system", "correct": true}, {"text": "That its competitor will try to disable her business\u2019 computer system", "correct": false}, {"text": "None of the above", "correct": false}]}], "case_study": {"body": [], "video": "assets/videos/m10-critical-cyber-threats-case-study.mp4", "poster": "assets/posters/m10-critical-cyber-threats-case-study.jpg"}, "images": ["assets/images/m10-critical-cyber-threats-hero.png"], "has_results": true}, {"number": 11, "name": "Defense Against Hackers", "description": ["\u201dThe best defense is a good offense\u201d. Rather than reacting to attacks once they\u2019ve occurred, a wise strategy is to prepare proactive measures, so that if the time comes, you can completely bypass the attack or lessen the blow of it."], "lessons": [{"title": "Cryptography", "body": ["Cryptography is basically defined as a secret method of writing. This is done so that only authorized parties are able to interpret the message.\nIt is used in various industries, such as banking and health to protect the privacy and security of companies and customers\u2019/patients\u2019 information.\nExamples of encryption methods include:\n\u00b7\tInternational Data Encryption Algorithm (IDEA)\n\u00b7\tAdvanced Encryption Standard (AES)\n\u00b7\tData Encryption Standard (DES)"], "images": []}, {"title": "Digital Forensics", "body": ["By many, computer systems have become a tool for committing various crimes. Because of this, law enforcement officials have decided to use this very tool to counteract the criminals\u2019 use of computers to commit online and offline crimes. In essence, they have decided to \u201cFight fire with fire\u201d.\nIn digital forensics, law enforcement collects and analyzes the data in such a way that it can be used in court against the perpetrator.\nExamples of cases where digital forensics was used:\n\u00b7\tBTK Killer: Dennis Rader was convicted of a string of serial killings that occurred over a period of sixteen years. Towards the end of this period, Rader sent letters to the police on a floppy disk. Metadata within the documents implicated an author named \\\\"], "images": []}, {"title": "Intrusion Detection", "body": ["Intrusion detection is a vital asset to a computer system. Intrusion detection systems (IDSs) inform the administrator or a security information and event management system of unauthorized programs or people on the network. There are a variety of IDSs to choose from.\nWhen looking to invest in an IDS, there are several questions to ask yourself.\n\u00b7\tWhat does our business need in an IDS?\n\u00b7\tWill our network support the IDS system?\n\u00b7\tCan we afford an IDS?\n\u00b7\tWhat do we do if something goes wrong with the IDS?\n\u00b7\tAs our business grows, we can still use this IDS?\nSome manufacturers of IDSs include:\n\u00b7\tDakota Alert, Inc.\n\u00b7\tJuniper Networks\n\u00b7\tLinear, LLC\n\u00b7\tPureTech Systems, Inc.\n\u00b7\tTelguard"], "images": []}, {"title": "Legal Recourse", "body": ["The majority of computer hacking crimes are punishable under the Computer Fraud and Abuse Act (18 U.S.C. \u00a71030). There may be additional penalties under state law.\nUnder this act, there are penalties for committing the following offenses involving computer:\n\u00b7\tObtaining National Security Information\n\u00b7\tAccessing a Computer and Obtaining Information\n\u00b7\tTrespassing in a Government Computer\n\u00b7\tAccessing a Computer to Defraud & Obtain Value\n\u00b7\tIntentionally Damaging by Knowing Transmission\n\u00b7\tRecklessly Damaging by Intentional Access\n\u00b7\tNegligently Causing Damage & Loss by Intentional Access\n\u00b7\tTrafficking in Passwords\n\u00b7\tExtortion Involving Computers\nPenalties may include monetary and/or prison sentences. For example, an individual who is found guilty of a first offense of illegally obtaining national security information can serve up to 10 years in prison."], "images": []}], "quizzes": [{"question": "What is cryptography?", "choices": [{"text": "Secret method of hearing", "correct": false}, {"text": "Secret method of speaking", "correct": false}, {"text": "Secret method of writing", "correct": true}, {"text": "Secret method of seeing", "correct": false}]}, {"question": "Which of these is NOT an encryption method mentioned in the \u201cCryptography\u201d lesson?", "choices": [{"text": "IDEA", "correct": false}, {"text": "YAR", "correct": true}, {"text": "AES", "correct": false}, {"text": "DES", "correct": false}]}, {"question": "The \u201cDigital Forensics\u201d lesson says that who collects and analyzes the data?", "choices": [{"text": "Company CEO", "correct": false}, {"text": "Independent forensics specialists", "correct": false}, {"text": "Company employees", "correct": false}, {"text": "Law enforcement", "correct": true}]}, {"question": "In the Sharon Lopatka example in \u201cDigital Forensics\u201d lesson, who was found to be the person who murdered her?", "choices": [{"text": "Robert Glass", "correct": true}, {"text": "Lisa Billingsley", "correct": false}, {"text": "John Smith", "correct": false}, {"text": "Renee Porter", "correct": false}]}, {"question": "What is NOT a question that the \u201cIntrusion Detection\u201d lesson states that one must ask before investing in an IDS?", "choices": [{"text": "What does our business need in an IDS?", "correct": false}, {"text": "Does state law allow our business to have an IDS?", "correct": true}, {"text": "Can we afford an IDS?", "correct": false}, {"text": "Will our network support the IDS system?", "correct": false}]}, {"question": "Which of these companies is mentioned as a manufacturer of IDSs?", "choices": [{"text": "Dakota Alert, Inc.", "correct": false}, {"text": "Juniper Networks", "correct": false}, {"text": "Linear, LLC", "correct": false}, {"text": "All of the above", "correct": true}]}, {"question": "The majority of computer hacking crimes are punishable under:", "choices": [{"text": "Computer Fraud and Abuse Act", "correct": true}, {"text": "Civil Rights Act", "correct": false}, {"text": "National Security Act", "correct": false}, {"text": "Workforce Investment Act", "correct": false}]}, {"question": "The \u201cLegal Recourse\u201d lesson states there are penalties for committing the following offenses involving computer:", "choices": [{"text": "Trafficking in Passwords", "correct": false}, {"text": "Accessing a Computer to Defraud & Obtain Value", "correct": false}, {"text": "Recklessly Damaging by Intentional Access", "correct": false}, {"text": "All of the above", "correct": true}]}, {"question": "What method of defense does Frank say they should consider?", "choices": [{"text": "VPN", "correct": false}, {"text": "Anti-Virus software", "correct": false}, {"text": "Encryption", "correct": true}, {"text": "Anti-Spyware software", "correct": false}]}, {"question": "What do intrusion detection systems do?", "choices": [{"text": "Notify the intruder that he/she will be arrested", "correct": false}, {"text": "Notify the company of suspicious activity", "correct": true}, {"text": "Notify the company that an intrusion report has been sent to the federal government", "correct": false}, {"text": "Notify the intruder that the company is aware of his/her presence and will be fining them", "correct": false}]}], "case_study": {"body": [], "video": "assets/videos/m11-defense-against-hackers-case-study.mp4", "poster": "assets/posters/m11-defense-against-hackers-case-study.jpg"}, "images": ["assets/images/m11-defense-against-hackers-hero.jpg"], "has_results": true}], "closing": {"name": "Wrapping Up", "body": ["Words from the Wise\n\u00b7\tKevin Mitnick: Somebody could send you an office document or a PDF file, and as soon as you open it, it's a booby trap and the hacker has complete control of your computer. Another major problem is password management. People use the same password on multiple sites, so when the hacker compromises one site, they have your password for everywhere else.\n\u00b7\tFrank Abagnale: The police can't protect consumers. People need to be more aware and educated about identity theft. You need to be a little bit wiser, a little bit smarter and there's nothing wrong with being skeptical. We live in a time when if you make it easy for someone to steal from you, someone will", "Although this workshop is coming to a close, we hope that your journey to improve your Cyber Security  is just beginning. Please take a moment to review and update your action plan. This will be a key tool to guide your progress in the days, weeks, months, and years to come. We wish you the best of luck on the rest of your travels!"]}, "hero_images": ["assets/images/course-cover.png"]};
